// Compile weekly digest from Shopify data (Shopify Payments = all revenue in one place)
const shopifyData = $input.first().json;

// Parse Shopify orders
const orders = shopifyData.orders || [];
const totalOrders = orders.length;
const totalRevenue = orders.reduce((sum, order) => sum + parseFloat(order.total_price || 0), 0);
const avgOrderValue = totalOrders > 0 ? (totalRevenue / totalOrders).toFixed(2) : '0.00';

// Count fulfilled vs unfulfilled
const fulfilled = orders.filter(o => o.fulfillment_status === 'fulfilled').length;
const unfulfilled = totalOrders - fulfilled;

// Count top products
const productCounts = {};
orders.forEach(order => {
  (order.line_items || []).forEach(item => {
    productCounts[item.title] = (productCounts[item.title] || 0) + item.quantity;
  });
});
const topProducts = Object.entries(productCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, qty]) => name + ' (' + qty + ' sold)')
  .join('\n  ');

// Payment breakdown
const paymentMethods = {};
orders.forEach(order => {
  (order.payment_gateway_names || []).forEach(gw => {
    paymentMethods[gw] = (paymentMethods[gw] || 0) + 1;
  });
});
const paymentBreakdown = Object.entries(paymentMethods)
  .map(([method, count]) => method + ': ' + count + ' orders')
  .join('\n  ');

const digest = `WEEKLY DIGEST — THE GREEN STANDARD\n` +
  `Week ending {{ $now.format('dd MMM yyyy') }}\n\n` +
  `ORDERS: ${totalOrders} (${fulfilled} fulfilled, ${unfulfilled} pending)\n` +
  `REVENUE: EUR ${totalRevenue.toFixed(2)}\n` +
  `AVG ORDER VALUE: EUR ${avgOrderValue}\n\n` +
  `TOP PRODUCTS:\n  ${topProducts || 'No sales this week'}\n\n` +
  `PAYMENT METHODS:\n  ${paymentBreakdown || 'N/A'}\n\n` +
  `---\n` +
  `Check Shopify admin and Klaviyo for detailed analytics.`;

return [{ json: { digest, totalOrders, totalRevenue, avgOrderValue } }];
